class Solution {
public:
    int numMusicPlaylists(int n, int goal, int k) {
        const int MOD = 1e9 + 7;
        vector<vector<int>> dp(goal + 1, vector<int>(n + 1, 0));
        dp[0][0] = 1;
        for (int i = 1; i <= goal; i++) {
            for (int j = 1; j <= n; j++) {
                if (j > i) break;
                if (j <= k + 1) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - 1] * (n - j + 1)) % MOD;
                } else {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - 1] * (n - j + 1) + dp[i - 1][j] * (j - k - 1)) % MOD;
                }
            }
        }
        int ans = 0;
        for (int j = 1; j <= n; j++) {
            ans = (ans + dp[goal][j]) % MOD;
        }
        return ans;
    }
};
